// // This module calculates the estimated cost to reach the goal from a given node based on the cost from the start node to the current node (g(n)) and the estimated cost from the current node to the goal (h(n)). However, it actually subtracts h(n) from g(n) instead of adding them.
module astar_heuristic (  
    input [7:0] g,  
    input [7:0] h,  
    output [8:0] f  
);  
    assign f = g + h;  
endmodule
